    lines.push("## Healthy Secrets");
    lines.push("");
    for (const s of report.ok) {
      lines.push(
        `- **${s.name}** — ${s.daysUntilExpiry} days remaining.`
      );
    }
    lines.push("");
  }

  return lines.join("\n");
