 */

import { describe, it, expect, beforeAll, afterAll } from "bun:test";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";

// ─── Configuration ────────────────────────────────────────────────────────────

const WORKSPACE = path.resolve(__dirname, "..");
const WORKFLOW_PATH = path.join(WORKSPACE, ".github/workflows/secret-rotation-validator.yml");
const ACT_RESULT_PATH = path.join(WORKSPACE, "act-result.txt");

// ─── Helpers ──────────────────────────────────────────────────────────────────

/** Append a delimited block to act-result.txt */
function appendActResult(label: string, output: string, exitCode: number): void {
  const block = [
    `\n${"=".repeat(80)}`,
    `TEST CASE: ${label}`,
    `EXIT CODE: ${exitCode}`,
    `TIMESTAMP: ${new Date().toISOString()}`,
    `${"=".repeat(80)}`,
    output,
    `${"=".repeat(80)}\n`,
  ].join("\n");
  fs.appendFileSync(ACT_RESULT_PATH, block, "utf8");
}

/**
 * Run `act push --rm` in a temp git repo containing the project files
 * plus optionally a custom fixture file. Returns { stdout, exitCode }.
 *
 * We copy the workspace into a temp dir so each test case is isolated.
 */
function runActInTempRepo(
  label: string,
  options: {
    fixtureFile?: string; // path to fixture, relative to workspace
    env?: Record<string, string>;
    timeoutMs?: number;
  } = {}
): { stdout: string; exitCode: number } {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "secret-rotation-"));

  try {
    // Copy the workspace into tmpDir (exclude node_modules and act-result.txt)
    const rsyncResult = spawnSync(
      "rsync",
      [
        "-a",
        "--exclude=node_modules",
        "--exclude=act-result.txt",
        "--exclude=.git",
        `${WORKSPACE}/`,
        `${tmpDir}/`,
      ],
      { encoding: "utf8" }
    );
    if (rsyncResult.status !== 0) {
      throw new Error(`rsync failed: ${rsyncResult.stderr}`);
    }

    // Initialize a git repo (act needs one)
    spawnSync("git", ["init"], { cwd: tmpDir, encoding: "utf8" });
    spawnSync("git", ["config", "user.email", "test@example.com"], {
      cwd: tmpDir,
      encoding: "utf8",
    });
    spawnSync("git", ["config", "user.name", "Test"], {
      cwd: tmpDir,
      encoding: "utf8",
    });
    spawnSync("git", ["add", "-A"], { cwd: tmpDir, encoding: "utf8" });
    spawnSync("git", ["commit", "-m", "test"], { cwd: tmpDir, encoding: "utf8" });

    // Build act command
    const actArgs = [
      "push",
      "--rm",
      "--no-cache-server",
      "-P",
      "ubuntu-latest=ghcr.io/catthehacker/ubuntu:act-latest",
    ];

    // Pass fixture as env var override if specified
    const envOverrides: Record<string, string> = {
      ...options.env,
    };
    if (options.fixtureFile) {
      envOverrides["FIXTURE_FILE"] = options.fixtureFile;
    }

    // Serialize env overrides as --env flags
    for (const [key, val] of Object.entries(envOverrides)) {
      actArgs.push("--env", `${key}=${val}`);
    }

    const result = spawnSync("act", actArgs, {
      cwd: tmpDir,
      encoding: "utf8",
      timeout: options.timeoutMs ?? 300_000, // 5 minutes
      maxBuffer: 50 * 1024 * 1024, // 50MB
    });

    const stdout = (result.stdout ?? "") + (result.stderr ?? "");
    const exitCode = result.status ?? 1;

    appendActResult(label, stdout, exitCode);

    return { stdout, exitCode };
  } finally {
    // Clean up temp dir
    fs.rmSync(tmpDir, { recursive: true, force: true });
  }
}

